# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from websockets import serve

class Item:
    def __init__(self, item_id, name):
        self.item_id = item_id
        self.name = name

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = {}

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def handle_client(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            action = data.get('action')
            if action == 'login':
                player_id = data['player_id']
                if player_id not in self.players:
                    self.players[player_id] = Player(player_id)
                await websocket.send(json.dumps({'status': 'success', 'message': 'Logged in'}))
            elif action == 'add_item':
                item_id = data['item_id']
                name = data['name']
                async with self.lock:
                    if item_id not in self.players[data['player_id']].inventory:
                        self.players[data['player_id']].inventory[item_id] = Item(item_id, name)
                        await websocket.send(json.dumps({'status': 'success', 'message': f'Item {name} added to inventory'}))
                    else:
                        await websocket.send(json.dumps({'status': 'error', 'message': f'Item {name} already exists in inventory'}))
            elif action == 'trade_item':
                from_player_id = data['from_player_id']
                to_player_id = data['to_player_id']
                item_id = data['item_id']
                async with self.lock:
                    if item_id in self.players[from_player_id].inventory:
                        self.players[to_player_id].inventory[item_id] = self.players[from_player_id].inventory.pop(item_id)
                        await websocket.send(json.dumps({'status': 'success', 'message': f'Item {item_id} traded from {from_player_id} to {to_player_id}'}))
                    else:
                        await websocket.send(json.dumps({'status': 'error', 'message': f'Item {item_id} does not exist in {from_player_id} inventory'}))

async def main():
    server = GameServer()
    async with serve(server.handle_client, "localhost", 8765):
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())